CustomField.formula:
IF(AND(RecordType.DeveloperName = "Client_Request", ISPICKVAL(Pickup_type__c, "Delivery")), "Red",
  IF(AND(OR(RecordType.DeveloperName = "Client_Request", RecordType.DeveloperName = "General_Delivery"), ISPICKVAL(Status__c, "Redelivery")), "Green",
    IF(AND(RecordType.DeveloperName = "General_Delivery", ISPICKVAL(SubType__c, "HOPE")), "Purple",
      IF(RecordType.DeveloperName = "Donation_Pickup", "Blue",
        IF(RecordType.DeveloperName = "General_Delivery", "Orange", null)
      )
    )
  )
)
